def title_case_format(text):
    if not text.strip():
        return text
    small_words = {"a", "an", "the", "of", "in", "on", "at", "to", "for", "and", "but", "or"}
    words = text.split()
    result = []
    for i, word in enumerate(words):
        lower = word.lower()
        if i == 0 or lower not in small_words:
            result.append(lower.capitalize())
        else:
            result.append(lower)
    return " ".join(result)

