import unittest

class TestSolution(unittest.TestCase):
    def test_basic_title(self):
        self.assertEqual(title_case_format("the lord of the rings"), "The Lord of the Rings")

    def test_all_uppercase_input(self):
        self.assertEqual(title_case_format("WAR AND PEACE"), "War and Peace")

    def test_first_word_small(self):
        self.assertEqual(title_case_format("a tale of two cities"), "A Tale of Two Cities")

    def test_hidden_empty_string(self):
        self.assertEqual(title_case_format(""), "")

    def test_hidden_single_word(self):
        self.assertEqual(title_case_format("hello"), "Hello")

    def test_hidden_single_small_word(self):
        self.assertEqual(title_case_format("the"), "The")

    def test_hidden_starts_with_small_word(self):
        self.assertEqual(title_case_format("in the beginning"), "In the Beginning")

    def test_hidden_mixed_case_input(self):
        self.assertEqual(title_case_format("pRiDe AND pReJuDiCe"), "Pride and Prejudice")

    def test_hidden_no_small_words(self):
        self.assertEqual(title_case_format("GREAT BIG WORLD"), "Great Big World")

    def test_hidden_multiple_small_words(self):
        self.assertEqual(title_case_format("an ode to the art of living"), "An Ode to the Art of Living")

if __name__ == '__main__':
    unittest.main()
